import{_ as e,o as t,c as n,ag as s}from"./chunks/framework.ePeAWSvT.js";const m=JSON.parse('{"title":"架构概览","description":"","frontmatter":{},"headers":[],"relativePath":"guide/architecture/index.md","filePath":"guide/architecture/index.md"}'),d={name:"guide/architecture/index.md"};function l(o,a,r,i,p,c){return t(),n("div",null,[...a[0]||(a[0]=[s(`<h1 id="架构概览" tabindex="-1">架构概览 <a class="header-anchor" href="#架构概览" aria-label="Permalink to &quot;架构概览&quot;">​</a></h1><p>本文描述 XnneHangLab 主项目 <code>src/lab/</code> 的整体分层与模块职责，方便快速定位代码。</p><hr><h2 id="分层结构" tabindex="-1">分层结构 <a class="header-anchor" href="#分层结构" aria-label="Permalink to &quot;分层结构&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>src/lab/</span></span>
<span class="line"><span>├── 入口层</span></span>
<span class="line"><span>│   ├── server.py                 # FastAPI 服务入口</span></span>
<span class="line"><span>│   └── streamlit/app.py          # Streamlit WebUI 入口</span></span>
<span class="line"><span>├── 通信层</span></span>
<span class="line"><span>│   ├── websocket_handler.py      # WebSocket 协议处理</span></span>
<span class="line"><span>│   └── message_handler.py        # 消息事件总线</span></span>
<span class="line"><span>├── 对话层</span></span>
<span class="line"><span>│   ├── conversations/            # 对话编排、TTS 管理、中断处理</span></span>
<span class="line"><span>│   └── service_context.py        # 会话上下文组装</span></span>
<span class="line"><span>├── 智能体层</span></span>
<span class="line"><span>│   └── agent/                    # Agent 框架、工具调度、记忆调用</span></span>
<span class="line"><span>└── 基础设施层</span></span>
<span class="line"><span>    ├── api/                      # HTTP 路由与客户端</span></span>
<span class="line"><span>    ├── asr/                      # FunASR / Whisper</span></span>
<span class="line"><span>    ├── config_manager/           # TOML 配置加载与校验</span></span>
<span class="line"><span>    ├── logger/                   # 分组日志</span></span>
<span class="line"><span>    ├── plugin/                   # 插件框架层</span></span>
<span class="line"><span>    ├── plugins/                  # 内置插件</span></span>
<span class="line"><span>    ├── profile/                  # Profile 与 system prompt 拼装</span></span>
<span class="line"><span>    ├── streamlit/                # Streamlit UI 页面与样式</span></span>
<span class="line"><span>    ├── tools/                    # BuiltinTool 与 ToolManager</span></span>
<span class="line"><span>    ├── utils/                    # 文本/音频工具函数</span></span>
<span class="line"><span>    └── cli/                      # CLI 工具</span></span></code></pre></div><hr><h2 id="请求流程" tabindex="-1">请求流程 <a class="header-anchor" href="#请求流程" aria-label="Permalink to &quot;请求流程&quot;">​</a></h2><p>一个典型的语音对话请求大致会经过这些阶段：</p><ol><li>客户端通过 <code>server.py</code> 建立 WebSocket 连接</li><li><code>websocket_handler.py</code> 解析协议并分发消息</li><li><code>conversations/</code> 创建和管理会话任务</li><li><code>service_context.py</code> 组装配置、Agent 与上下文</li><li><code>agent/</code> 调用 LLM，并按需使用工具、技能和记忆 hook</li><li>Agent 返回文本，再进入 TTS 与字幕链路</li><li>最终结果通过 WebSocket 回传给客户端</li></ol><hr><h2 id="模块速查" tabindex="-1">模块速查 <a class="header-anchor" href="#模块速查" aria-label="Permalink to &quot;模块速查&quot;">​</a></h2><table tabindex="0"><thead><tr><th>模块</th><th>路径</th><th>职责</th><th>详情</th></tr></thead><tbody><tr><td>Agent</td><td><code>agent/</code></td><td>LLM 调用、工具调度、记忆与生命周期</td><td><a href="./agent.html">→ agent</a></td></tr><tr><td>API</td><td><code>api/</code></td><td>HTTP 路由、TTS/ASR 客户端封装</td><td><a href="./api.html">→ api</a></td></tr><tr><td>ASR</td><td><code>asr/</code></td><td>FunASR / Whisper 语音识别</td><td><a href="./asr.html">→ asr</a></td></tr><tr><td>Conversations</td><td><code>conversations/</code></td><td>对话编排、TTS 管理、中断处理</td><td><a href="./conversations.html">→ conversations</a></td></tr><tr><td>Config</td><td><code>config_manager/</code></td><td>TOML 配置加载与校验</td><td><a href="./config.html">→ config</a></td></tr><tr><td>Tools</td><td><code>tools/</code> / <code>plugins/</code></td><td>BuiltinTool、工具插件与 ToolManager</td><td><a href="./tools.html">→ tools</a></td></tr><tr><td>Plugin System</td><td><code>plugin/</code> / <code>plugins/</code></td><td>插件发现、加载与类型分发</td><td><a href="./plugin-system.html">→ plugin-system</a></td></tr><tr><td>Profile System</td><td><code>profile/</code></td><td>persona、format、skill 注入</td><td><a href="./profile-system.html">→ profile-system</a></td></tr><tr><td>Skills</td><td><code>plugins/</code> / <code>profile/</code></td><td>SkillDescriptor 与 system prompt 注入</td><td><a href="./skills.html">→ skills</a></td></tr><tr><td>Memory Agent</td><td><code>agent/agents/memory_agent/</code></td><td>当前主 Agent 实现</td><td><a href="./memory-agent.html">→ memory-agent</a></td></tr></tbody></table><hr><h2 id="关键设计决策" tabindex="-1">关键设计决策 <a class="header-anchor" href="#关键设计决策" aria-label="Permalink to &quot;关键设计决策&quot;">​</a></h2><h3 id="单一-llm-provider-接口" tabindex="-1">单一 LLM Provider 接口 <a class="header-anchor" href="#单一-llm-provider-接口" aria-label="Permalink to &quot;单一 LLM Provider 接口&quot;">​</a></h3><p>项目保留统一的 OpenAI-compatible 调用方式，不把上层逻辑绑死在某一家 provider 上。这样模型源可以换，调用方式尽量别换。</p><h3 id="agent-memoryagent" tabindex="-1">Agent = MemoryAgent <a class="header-anchor" href="#agent-memoryagent" aria-label="Permalink to &quot;Agent = MemoryAgent&quot;">​</a></h3><p>当前主实现仍然是 <code>MemoryAgent</code>。<code>AgentFactory</code> 保留了工厂层，是为了让未来扩展更多 Agent 时不需要回头拆主流程。</p><h3 id="内置工具-插件工具" tabindex="-1">内置工具 + 插件工具 <a class="header-anchor" href="#内置工具-插件工具" aria-label="Permalink to &quot;内置工具 + 插件工具&quot;">​</a></h3><p>高频基础能力直接做成 <code>BuiltinTool</code>，比如读写文件、列目录、获取时间；联网搜索、网页抓取、截图这类能力则通过插件系统挂到 <code>ToolManager</code>。这样既轻，又保留可扩展性。</p><h3 id="skill-注入而不是硬编码流程" tabindex="-1">Skill 注入而不是硬编码流程 <a class="header-anchor" href="#skill-注入而不是硬编码流程" aria-label="Permalink to &quot;Skill 注入而不是硬编码流程&quot;">​</a></h3><p>Skill 不直接执行动作，而是通过 <code>SystemPromptBuilder</code> 注入操作指引。这样“怎么做事”的知识可以放进插件，而不是散落在代码分支里。</p><h3 id="对话中断" tabindex="-1">对话中断 <a class="header-anchor" href="#对话中断" aria-label="Permalink to &quot;对话中断&quot;">​</a></h3><p>系统支持中断控制，相关信号通过 <code>MessageHandler</code> 和会话层传递，让 TTS、字幕和对话状态能同步停下来。</p>`,24)])])}const g=e(d,[["render",l]]);export{m as __pageData,g as default};
